noncompliant:
// Noncompliant: Empty parameter list
void myFunction();

void anotherFunction() {
  // This can be called with unexpected parameters
  myFunction(42, "hello");  // Compiles but undefined behavior
}

compliant:
// Compliant: Explicit void parameter
void myFunction(void);

void anotherFunction(void) {
  myFunction();  // Can only be called without parameters
}
